import java.sql.*;   // Importing necessary classes 

   

public class java_51158_JDBCQueryHandler_A03 {     // Declaring the main Java Class name as 'JDBC' for simplicity purpose here and naming according to PEP8 standards of coding style - snake_case preferred over camel case in java. Eg: jdbcDriverExample, DataBaseConnectionManager etc 

    private static final String url = "jdbc:mysql://localhost/testdb";   // Connection URL for MySQL database on localhost with the name 'testDB' to be used later here and according PEP8 standards of coding style - snake_case preferred over camel case in java. Eg:'databaseURL', serverDetails etc 

    private static final String username = "root";                      // Database Username for MySQL database   eg: userName, 'username' can be used as per the requirement to make code more readable and maintainability by convention which is snake_case preferred over camel case in java. Eg:'databaseUser', dbCredentials etc 

    private static final String password = "password";                   // Database Password for MySQL database   eg: userPassword, 'passwords' can be used as per the requirement to make code more readable and maintainability by convention which is snake_case preferred over camel case in java
    

public class Main { 

    public static void main(String[] args) // Defining a method named `main`, where execution begins for our application. This function will be called when 'java' command line executed to run this program from the terminal/cmd shell - JVM is started and Java Virtual Machine (JVM), Runtime objects are used here
     {   
            try{  // Create a Connection object using class `DriverManager`   --> Here we need java.sql.* package which can be imported automatically by Oracle Database Driver so it will not directly execute this line of code, hence added exception handling for debugging purpose in case any error happens there
             Class.forName("com.mysql.cj.jdk.driver");  // Loading MySQL JDBC driver   --> Here we are using the class name 'org' which is redundant and not recommended to use as per Java naming conventions, hence added exception handling for debugging purpose
             Connection con = DriverManager.getConnection(url, username , password);   
            Statement stmt=con.createStatement();  // Create a SQL statement object using the connection we obtained above     --> This is to be used whenever there are queries in our program and it executes them automatically  
              String sql = "INSERT INTO Employee (id,name) VALUES ('1', 'John')";   
            stmt.executeUpdate(sql); // Execute SQL statement using `stmt` object  --> This will insert data into database with the specified query above     - The inserted values are auto-generated by Oracle DB and it is not controlled directly
             }catch (Exception e){   // Catch exception if there occurs any, so we can debug our program effectively. Here 'e' represents an object of Exception class  --> We use this catch block to handle exceptions in the code which otherwise would crash due unforeseen errors or bugs and will help us figure out what went wrong
             e.printStackTrace(); // This statement prints error message for that exception on console/cmd shell   - 'e' represents an object of Exception class  --> We use this to debug our program effectively by printing the stack trace which contains information about specific point in time when something goes wrong with execution and what kind of errors have occurred
            }
        }     // Closing `try-catch` statement for error handling purposes. If there is any exception then it will catch here, otherwise continue to next line code    --> Here 'con' represents Connection object which can be used in multiple threads – JVM handles all of this internally and we do not need external resources/threads manually

        }   // Closing the main method - Java requires a `main` function for program start, here it is closed. We are ending our application with 'exit' statement on console as per PEP8 standards – snake_case preferred over camel case in java and also used to stop JVM from running

        // End of Main Method - Java requires a `main` function for program start, here it is closed. We are ending our application with 'exit' statement on console as per PEP8 standards – snake_case preferred over camel case in java and also used to stop JVM from running

} // End of Class Main - Java requires a `main` function for program start, here it is closed. We are ending our application with 'exit' statement on console as per PEP8 standards – snake_case preferred over camel case in java and also used to stop JVM from running